return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'de_formal','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Bitte aktualisieren Sie das TranslatePress - Multilingual-Plugin auf Version %1$s oder höher, damit %2$s ordnungsgemäß funktioniert.','Please install and activate the TranslatePress - Multilingual plugin'=>'Bitte installieren und aktivieren Sie das TranslatePress - Multilingual-Plugin.','Install & Activate'=>'Installieren & Aktivieren','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Bitte aktualisieren Sie TranslatePress - Multilingual auf Version %2$s oder neuer. Ihre derzeit installierte Version von TranslatePress - Multilingual ist nicht mehr mit der aktuellen Version von %1$s kompatibel.','All TranslatePress functionalities are disabled until then.'=>'Alle TranslatePress-Funktionen sind bis dahin deaktiviert.','Update Now'=>'Jetzt aktualisieren','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Dieses TranslatePress-Add-on wurde in das Haupt-Plugin migriert und wird nicht mehr verwendet. Sie können es löschen.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> benötigt zur Ausführung mindestens PHP-Version 5.6.20+. Dies ist die <a href="%s">Mindestvoraussetzung der neuesten WordPress-Version</a>. Bitte wenden Sie sich an Ihren Server-Administrator, um Ihre PHP-Version zu aktualisieren.','Advanced'=>'Erweitert','Settings saved.'=>'Einstellungen gespeichert.','Are you sure you want to remove this item?'=>'Sind Sie sicher, dass Sie dieses Element entfernen möchten?','Remove'=>'Entfernen','Add'=>'Hinzufügen','Select...'=>'Auswählen...','[%s] Low TranslatePress AI Words'=>'[%s] Wenige TranslatePress AI-Wörter','upgrade your plan or get extra AI Words'=>'Ihren Plan upgraden oder zusätzliche AI-Wörter erhalten','upgrade your plan'=>'Plan upgraden','TranslatePress AI words are running low on your site.'=>'Die TranslatePress AI-Wörter auf Ihrer Website werden knapp.','Current status: %s words remaining'=>'Aktueller Status: %s verbleibende Wörter','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Sobald die verbleibenden AI-Wörter aufgebraucht sind, wird die automatische Übersetzung durch TranslatePress AI pausiert.','To continue translating your content, please %1$s over at %2$s'=>'Um Ihre Inhalte weiterhin zu übersetzen, %1$s Sie bitte auf %2$s.','Manage Notification: %s'=>'Benachrichtigung verwalten: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Eine neue Version von %1$s ist verfügbar. %2$sDetails zu Version %3$s anzeigen%4$s oder %5$sjetzt aktualisieren%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Eine neue Version von %1$s ist verfügbar. %2$sDetails zu Version %3$s anzeigen%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Um Aktualisierungen zu ermöglichen, %1$sgeben Sie bitte Ihren Lizenzschlüssel ein%2$s. Benötigen Sie einen Lizenzschlüssel? %3$sJetzt erwerben%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Um Aktualisierungen zu ermöglichen, besuchen Sie bitte die %1$sLizenzseite%2$s und prüfen Sie, ob Sie eine gültige Lizenz haben.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Um Aktualisierungen zu ermöglichen, muss Ihre Lizenz erneuert werden. Bitte besuchen Sie die Seite %1$sTranslatePress Account%2$s und melden Sie sich an, um die Lizenz zu erneuern.','You do not have permission to install plugin updates'=>'Sie haben keine Berechtigung, Plugin-Aktualisierungen zu installieren.','Error'=>'Fehler','Your TranslatePress license key is invalid or missing.'=>'Ihr TranslatePress-Lizenzschlüssel ist ungültig oder fehlt.','Your license key expired on %s.'=>'Ihr Lizenzschlüssel ist am %s abgelaufen.','Your license key has been disabled.'=>'Ihr Lizenzschlüssel wurde deaktiviert.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Ihr Lizenzschlüssel ist für diese URL deaktiviert. Reaktivieren Sie ihn über <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Seiten verwalten.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Lizenzschlüssel stimmt nicht überein.</strong> Die eingegebene Lizenz entspricht nicht der installierten TranslatePress-Version.</p><p>Bitte prüfen Sie, ob Sie die für Ihre Lizenz passende Version aus Ihrem TranslatePress Account installiert haben.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Wenn Sie nur das kostenlose Plugin installiert haben, aber eine kostenpflichtige Lizenz hinzugefügt haben, installieren Sie bitte das kostenpflichtige Plugin aus Ihrem TranslatePress Account.','Your license key has reached its activation limit.'=>'Ihr Lizenzschlüssel hat das Aktivierungslimit erreicht.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Upgraden Sie Ihren Plan, um weitere Webseiten hinzuzufügen. %1$sJetzt upgraden%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Diese Website wurde bereits unter einer kostenlosen Lizenz aktiviert. Jede Website kann nur eine kostenlose Lizenz nutzen.','An error occurred, please try again.'=>'Es ist ein Fehler aufgetreten. Bitte versuchen Sie es erneut.','You have successfully activated your license'=>'Sie haben Ihre Lizenz erfolgreich aktiviert.','Others'=>'Andere','Restrict by Language'=>'Nach Sprache einschränken','Exclude from Language'=>'Aus Sprache ausschließen','Restrict element to language'=>'Element auf Sprache einschränken','Show this element only in one language.'=>'Dieses Element nur in einer Sprache anzeigen.','Enable translation'=>'Übersetzung aktivieren','Allow translation to the corresponding language only if the content is written in the default language.'=>'Erlaubt die Übersetzung in die entsprechende Sprache nur, wenn der Inhalt in der Standardsprache verfasst ist.','Select language'=>'Sprache auswählen','Choose in which language to show this element.'=>'Wählen Sie, in welcher Sprache dieses Element angezeigt werden soll.','Exclude element from language'=>'Element aus Sprache ausschließen','Exclude this element from specific languages.'=>'Dieses Element aus bestimmten Sprachen ausschließen.','Select languages'=>'Sprachen auswählen','Choose from which languages to exclude this element.'=>'Wählen Sie, aus welchen Sprachen dieses Element ausgeschlossen werden soll.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Dieses Element bleibt sichtbar, wenn Sie Ihre Website über den Übersetzungs-Editor übersetzen.','The content of this element should be written in the default language.'=>'Der Inhalt dieses Elements sollte in der Standardsprache verfasst sein.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> ist auf SQL-Fehler gestoßen. <a href="%s" title="View TranslatePress SQL Errors">Fehler anzeigen</a>.','Automatic translation has been disabled.'=>'Die automatische Übersetzung wurde deaktiviert.','Dismiss this notice.'=>'Diesen Hinweis ausblenden.','Logged errors'=>'Protokollierte Fehler','These are the most recent 5 errors logged by TranslatePress:'=>'Dies sind die letzten 5 von TranslatePress protokollierten Fehler:','Yes'=>'Ja','Why are these errors occuring'=>'Warum treten diese Fehler auf','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Wenn TranslatePress bei der Ausführung von Abfragen in Ihrer Datenbank ein Problem feststellt, kann es die Funktion für automatische Übersetzungen deaktivieren, um zusätzliche Kosten bei Google/DeepL zu vermeiden. Die automatische Übersetzung muss manuell aktiviert werden, nachdem Sie die Probleme behoben haben.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Die festgestellten SQL-Fehler können aus verschiedenen Gründen auftreten, darunter fehlende Tabellen, fehlende Berechtigungen für den SQL-Benutzer zum Erstellen von Tabellen oder zum Ausführen anderer Operationen, Probleme nach einer Website-Migration oder Änderungen an der SQL-Server-Konfiguration.','What you can do in this situation'=>'Was Sie in dieser Situation tun können','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Gehen Sie zu Einstellungen -> TranslatePress -> Registerkarte Allgemein und speichern Sie die Einstellungen. Dadurch werden die Tabellen mit Ihren aktuellen SQL-Einstellungen neu generiert. Prüfen Sie, ob beim Surfen auf Ihrer Website in einer übersetzten Sprache keine weiteren Fehler mehr auftreten. Achten Sie auf die Zeitstempel der Fehler, um sicherzustellen, dass Sie nicht die alten Fehler sehen. Es werden nur die 5 neuesten Fehler angezeigt.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Wenn Ihr Problem nicht gelöst ist, versuchen Sie die folgenden Schritte:','Create a backup of your database'=>'Erstellen Sie eine Sicherung Ihrer Datenbank','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Erstellen Sie eine Kopie jeder Übersetzungstabelle, in der Fehler auftreten. Sie können die Tabelle innerhalb derselben Datenbank kopieren (z. B. trp_dictionary_en_us_es_es_COPY) – führen Sie diesen Schritt nur aus, wenn Sie die aktuellen Übersetzungen behalten möchten)','Remove the trouble tables by executing the DROP function on them'=>'Entfernen Sie die fehlerhaften Tabellen, indem Sie die DROP-Funktion auf sie anwenden','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Gehen Sie zu Einstellungen -> TranslatePress -> Registerkarte Allgemein und speichern Sie die Einstellungen. Dadurch werden die Tabellen mit Ihrem aktuellen SQL-Server neu generiert.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Kopieren Sie den relevanten Inhalt aus den duplizierten Tabellen (z. B. trp_dictionary_en_us_es_es_COPY) in die neu generierte Tabelle (trp_dictionary_en_us_es_es) – führen Sie diesen Schritt nur aus, wenn Sie die aktuellen Übersetzungen behalten möchten)','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Testen Sie, ob alles funktioniert. Wenn etwas schiefgelaufen ist, können Sie das Backup wiederherstellen, das Sie im ersten Schritt erstellt haben. Prüfen Sie, ob beim Surfen auf Ihrer Website in einer übersetzten Sprache keine weiteren Fehler mehr auftreten. Achten Sie auf die Zeitstempel der Fehler, um sicherzustellen, dass Sie nicht die alten Fehler sehen. Es werden nur die 5 neuesten Fehler angezeigt.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Wenn Ihr Problem immer noch nicht gelöst ist, fragen Sie Ihren Hosting-Anbieter nach den Fehlern. Das häufigste Problem sind fehlende Berechtigungen für den SQL-Benutzer, wie z. B. die Berechtigung zum Erstellen von Tabellen.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Installation fehlgeschlagen. Versuchen Sie es erneut über die <a href="%s" >Plugin-Übersicht.</a>','Active'=>'Aktiv','Permission denied.'=>'Zugriff verweigert.','Invalid nonce.'=>'Ungültiger nonce.','Settings scope unknown.'=>'Einstellungsbereich unbekannt.','Legacy disabled.'=>'Legacy deaktiviert.','Language Switcher'=>'Sprachumschalter','Change language to %s'=>'Sprache auf %s ändern','Automatic Translation'=>'Automatische Übersetzung','DeepL'=>'DeepL','Unsupported languages'=>'Nicht unterstützte Sprachen','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Die ausgewählte automatische Übersetzung unterstützt diese Sprachen nicht.<br>Sie können Seiten in diesen Sprachen weiterhin manuell mit dem Übersetzungseditor übersetzen.','API key validation failed.'=>'Validierung des API-Schlüssels fehlgeschlagen.','API key verification was successful.'=>'Der API-Schlüssel wurde erfolgreich verifiziert.','Please enter your Google Translate key.'=>'Bitte geben Sie Ihren Google Translate-Schlüssel ein.','Please enter your DeepL API key.'=>'Bitte geben Sie Ihren DeepL API-Schlüssel ein.','Not TranslatePress onboarding page.'=>'Keine TranslatePress-Onboarding-Seite.','Step %s does not exist'=>'Schritt %s existiert nicht','Welcome'=>'Willkommen','Add Languages'=>'Sprachen hinzufügen','Enable Addons'=>'Addons aktivieren','Finalize'=>'Fertigstellen','Exit Setup'=>'Einrichtung beenden','Upgrade'=>'Upgrade','Nothing here'=>'Hier ist nichts','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Ihre <strong>TranslatePress</strong>-Lizenz fehlt oder ist ungültig. <br/>Bitte %1$sregistrieren Sie Ihre Kopie%2$s, um automatische Übersetzungen Ihrer Website via TranslatePress AI, Premium-Addons, automatische Updates und Support zu aktivieren. Benötigen Sie einen Lizenzschlüssel? %3$sJetzt erwerben%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Ihre <strong>TranslatePress</strong>-Lizenz läuft am %1$s ab. Bitte %2$sverlängern Sie Ihre Lizenz%3$s, um weiterhin Zugriff auf automatische Übersetzungen via TP AI, Premium-Addons, Produktdownloads und automatische Updates zu erhalten. %4$sJetzt verlängern%5$s','Error: '=>'Fehler: ','Something went wrong, please try again.'=>'Ein Fehler ist aufgetreten, bitte versuchen Sie es erneut.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Ihre <strong>TranslatePress</strong>-Lizenz ist abgelaufen. <br/>Bitte %1$sverlängern Sie Ihre Lizenz%2$s, um weiterhin Zugriff auf automatische Übersetzungen via TranslatePress AI, Premium-Addons, Produktdownloads und automatische Updates zu erhalten. %3$sJetzt verlängern %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Der Lizenzschlüssel stimmt nicht überein. Die eingegebene Lizenz entspricht nicht der installierten <strong>%1$s</strong>-Version. <br/>Bitte überprüfen Sie, ob Sie die korrekte Version für Ihre Lizenz aus Ihrem %2$sTranslatePress Account%3$s installiert haben.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Falls Sie nur das kostenlose Plugin installiert haben, aber eine kostenpflichtige Lizenz hinzugefügt haben, installieren Sie bitte das kostenpflichtige Plugin aus Ihrem TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Sie haben das Aktivierungslimit für Ihre <strong>%1$s</strong>-Lizenz erreicht. <br/>Verwalten Sie Ihre aktiven Websites über %2$s Ihren Account %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Ihre Lizenz ist für diese URL deaktiviert. Reaktivieren Sie sie über <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Websites verwalten.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Die automatische Übersetzung von %1$s erfordert eine aktive Lizenz. Bitte %2$sverlängern Sie Ihre Lizenz%3$s oder erwerben Sie eine neue %4$shier%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Bitte %1$sgeben Sie Ihren Lizenzschlüssel ein%2$s, um die automatische Übersetzung von %3$s zu aktivieren.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Sie haben noch weniger als 5.000 TranslatePress AI-Wörter übrig. Um Ihre Website weiterhin automatisch zu übersetzen, bitte %serwerben Sie zusätzliche AI-Wörter zu einem ermäßigten Preis aus Ihrem Account%s.',' Error: '=>' Fehler: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Diese Website wurde bereits unter einer kostenlosen Lizenz aktiviert. Pro Website kann nur eine kostenlose Lizenz verwendet werden. Bitte upgraden Sie auf einen Premium-Tarif für mehr TranslatePress AI-Wörter über %1$s Ihren Account %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Sie haben keine gültige Lizenz für <strong>TranslatePress</strong>. %1$sHolen Sie sich eine kostenlos%2$s, um Zugriff auf TranslatePress AI zu erhalten.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NEU:</strong> Das <strong>Different Domain per Language</strong>-Add-on ist da! Steigern Sie Ihr globales SEO und schaffen Sie ein lokales Erlebnis mit länderspezifischen Domains wie .de oder .fr. Upgraden Sie auf <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business oder Developer</a>, um darauf zuzugreifen und weitere Premium-Vorteile zu erhalten!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NEU:</strong> Das <strong>Different Domain per Language</strong>-Add-on ist da! Steigern Sie Ihr globales SEO und schaffen Sie ein lokales Erlebnis mit länderspezifischen Domains wie .de oder .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Mehr erfahren</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Das tägliche Kontingent für Maschinenübersetzungszeichen wurde überschritten. Bitte prüfen Sie die Seite <strong>TranslatePress -> <a href="%s">Automatische Übersetzung</a></strong> für weitere Informationen.','Marketing optin'=>'Marketing-Opt-in','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Melden Sie sich für Benachrichtigungen zu Sicherheits- und Funktionsupdates sowie für nicht sensible Diagnose-Tracking an.','TranslatePress Preferred User Language'=>'Bevorzugte Benutzersprache in TranslatePress','Preferred language to navigate the site'=>'Bevorzugte Sprache zum Navigieren auf der Website','The language is automatically set based by the last visited language by the user.'=>'Die Sprache wird automatisch basierend auf der zuletzt vom Benutzer besuchten Sprache festgelegt.','Always use this language'=>'Immer diese Sprache verwenden','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Wenn Sie diese Einstellung aktivieren, bleibt die bevorzugte Sprache die oben ausgewählte; eine Änderung im Frontend ist nicht möglich.<br>Diese Sprache wird bei verschiedenen Vorgängen verwendet, z. B. beim Senden von E-Mails an den Benutzer.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Hallo! Sie scheinen <strong>TranslatePress</strong> bereits seit einiger Zeit zum Übersetzen Ihrer Website zu verwenden. Das ist großartig! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Wenn Sie sich ein paar Minuten Zeit nehmen könnten, um es auf WordPress.org zu bewerten, würde uns das sehr helfen (und meine Motivation steigern).','~ Razvan, developer of TranslatePress'=>'~ Razvan, Entwickler von TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'TranslatePress auf der Plugin-Seite von WordPress.org bewerten','Ok, I will gladly help!'=>'OK, ich helfe gerne!','No, thanks.'=>'Nein, danke.','Full Language Names'=>'Vollständige Sprachnamen','Short Language Names'=>'Kurze Sprachnamen','Flags with Full Language Names'=>'Flaggen mit vollständigen Sprachnamen','Flags with Short Language Names'=>'Flaggen mit kurzen Sprachnamen','Only Flags'=>'Nur Flaggen','Full Language Names No HTML'=>'Vollständige Sprachnamen ohne HTML','Bottom Right'=>'Unten rechts','Bottom Left'=>'Unten links','Top Right'=>'Oben rechts','Top Left'=>'Oben links','Dark'=>'Dunkel','Light'=>'Hell','Deactivate'=>'Deaktivieren','Activate'=>'Aktivieren','Invalid language code. Please try again.'=>'Ungültiger Sprachcode. Bitte versuchen Sie es erneut.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Sprachcodes dürfen nur die Zeichen A-Z a-z 0-9 - _ enthalten. Überprüfen Sie Ihre Sprachcodes in den allgemeinen Einstellungen von TranslatePress.','Error! Duplicate URL slug values.'=>'Fehler! Doppelte URL-Slug-Werte.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Sie können nicht zwei Sprachen auswählen, die denselben <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">ISO-Code</a> haben, sich aber in der Formalität unterscheiden, da dies zu doppelten <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang-Tags</a> führen würde.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Doppelte Sprache erkannt.<br>Jede Sprache kann nur einmal hinzugefügt werden, um eine korrekte Übersetzungsverwaltung zu gewährleisten.<br> Bitte ändern Sie den doppelten Spracheintrag und versuchen Sie es erneut. ','Current Language'=>'Aktuelle Sprache','Opposite Language'=>'Entgegengesetzte Sprache','General'=>'Allgemein','Translate Site'=>'Website übersetzen','Addons'=>'Add-ons','License'=>'Lizenz','Settings'=>'Einstellungen','Activate License'=>'Lizenz aktivieren','Pro Features'=>'Pro-Funktionen','Need Help?'=>'Benötigen Sie Hilfe?','Recent community discussions'=>'Aktuelle Community-Diskussionen','Loading...'=>'Wird geladen...','Unable to load forum posts'=>'Forum-Beiträge können nicht geladen werden.','Ask a Question'=>'Frage stellen','View All Topics'=>'Alle Themen anzeigen','by'=>'von','Have a question?'=>'Haben Sie eine Frage?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Erhalten Sie direkt Hilfe von den Plugin-Entwicklern, schlagen Sie Verbesserungen vor oder teilen Sie Ihr Feedback!','Tip for faster help:'=>'Tipp für schnellere Hilfe:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Beschreiben Sie, was Sie versucht haben, was Sie erwartet haben und was passiert ist. Screenshots helfen!','Toggle support chat'=>'Support-Chat ein-/ausblenden','Ask the community'=>'Fragen Sie die Community','Close'=>'Schließen','Empty feed response'=>'Leere Feed-Antwort','Unable to parse feed'=>'Der Feed konnte nicht verarbeitet werden.','Just now'=>'Gerade eben','%d hour ago'=>'Vor %d Stunde' . "\0" . 'Vor %d Stunden','%d day ago'=>'Vor %d Tag' . "\0" . 'Vor %d Tagen','Source'=>'Quelle','Srcset'=>'Srcset','Alt attribute'=>'Alt-Attribut','Title attribute'=>'Titel-Attribut','Anchor link'=>'Anker-Link','Placeholder attribute'=>'Platzhalter-Attribut','Submit attribute'=>'Submit-Attribut','Text'=>'Text','Video Poster'=>'Video-Poster','plural form'=>'Pluralform','one'=>'Eins','few'=>'Wenige','many'=>'Viele','other'=>'Andere','Saved'=>'Gespeichert','Save'=>'Speichern','Saving translation...'=>'Übersetzung wird gespeichert...','You have unsaved changes!'=>'Sie haben ungespeicherte Änderungen!','Discard changes'=>'Änderungen verwerfen','Discard All'=>'Alle verwerfen','Loading Strings...'=>'Strings werden geladen...','Select string to translate...'=>'Wählen Sie einen String zur Übersetzung aus...','Close Editor'=>'Editor schließen','From'=>'Von','To'=>'In','Add Media'=>'Medien hinzufügen','Other languages'=>'Andere Sprachen','Context'=>'Kontext','View Website As'=>'Website anzeigen als','Available in our Pro Versions'=>'Verfügbar in unseren Pro-Versionen','Select or Upload Media'=>'Medien auswählen oder hochladen','Use this media'=>'Dieses Medium verwenden','Translate'=>'Übersetzen','Translate entire block element'=>'Gesamtes Blockelement übersetzen','Split block to translate strings individually'=>'Block teilen, um Strings einzeln zu übersetzen.','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Änderungen an der Übersetzung speichern. Tastenkürzel: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Zum nächsten String in der Dropdown-Liste navigieren. Tastenkürzel: CTRL(⌘) + ALT + Pfeiltaste nach rechts','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Zum vorherigen String in der Dropdown-Liste navigieren. Tastenkürzel: CTRL(⌘) + ALT + Pfeiltaste nach links','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Alle Änderungen verwerfen. Tastenkürzel: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Änderungen in diesem Textfeld verwerfen. Um Änderungen in allen Textfeldern zu verwerfen, verwenden Sie das Tastenkürzel: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Tooltip schließen','Quick Intro'=>'Kurze Einführung','Are you sure you want to split this phrase into smaller parts?'=>'Sind Sie sicher, dass Sie diesen Ausdruck in kleinere Teile aufteilen möchten?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Dieser String ist noch nicht für die Übersetzung bereit.<br>Versuchen Sie es in einem Moment erneut...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Damit diese Option funktioniert, aktualisieren Sie bitte das Add-on „Als andere Rolle durchsuchen“ auf die neueste Version.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Um Slugs zu übersetzen, aktualisieren Sie bitte das SEO Pack Add-on auf die neueste Version.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Sie können eine neue Sprache unter <a href="%s">Einstellungen->TranslatePress</a> hinzufügen.','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Sie können jedoch weiterhin TranslatePress verwenden, um <strong style="background: #f5fb9d;">Gettext-Strings zu ändern</strong>, die auf Ihrer Seite verfügbar sind.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Benutzererstellte Strings können nicht geändert werden, nur solche aus Themes und Plugins.','Extra Translation Features'=>'Zusätzliche Übersetzungsfunktionen','Support for 130+ Extra Languages'=>'Unterstützung für 130+ zusätzliche Sprachen','Access to TranslatePress AI'=>'Zugriff auf TranslatePress AI','Translate SEO Title, Description, Slug'=>'SEO-Titel, Beschreibung und Slug übersetzen','Publish only when translation is complete'=>'Nur veröffentlichen, wenn die Übersetzung abgeschlossen ist','Translate by Browsing as User Role'=>'Als Benutzerrolle durchsuchen und übersetzen','Different Menu Items for each Language'=>'Unterschiedliche Menüpunkte für jede Sprache','Automatic User Language Detection'=>'Automatische Erkennung der Benutzersprache','Upgrade to PRO'=>'Upgrade auf PRO','Upgrade to PRO with our biggest discount of the year!'=>'Upgrade auf PRO mit unserem größten Rabatt des Jahres!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'An diesem Black Friday erhalten Sie Zugriff auf diese Funktionen und mehr zu einem Bruchteil der Kosten:','No available suggestions'=>'Keine verfügbaren Vorschläge','Suggestions from translation memory'=>'Vorschläge aus dem Übersetzungsspeicher','Click to Copy'=>'Zum Kopieren klicken','Human Translation'=>'Menschliche Übersetzung','Machine Translation'=>'Maschinelle Übersetzung','Text on this page is %s% translated into all languages.'=>'Der Text auf dieser Seite ist zu %s% in alle Sprachen übersetzt.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% des Textes auf dieser Seite ist in %2$s übersetzt.','This page is %1$s% translated into %2$s.'=>'Diese Seite ist zu %1$s% in %2$s übersetzt.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Der Slug, den Sie bearbeiten möchten, ist in anderen Slug-Typen vorhanden:%s%. Wenn Sie ihn bearbeiten, wird jedes Vorkommen ersetzt, unabhängig vom aktuellen Typ.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Fahren Sie mit dem Mauszeiger über einen beliebigen Text auf der Seite, klicken Sie auf %s,<br> und bearbeiten Sie anschließend die Übersetzung in der Seitenleiste.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Vergessen Sie nicht, die Übersetzung zu speichern. Verwenden Sie die Tastenkombination CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Wechseln Sie die Sprache, um die Änderungen der Übersetzung direkt auf der Seite zu sehen.','Search for any text in this page in the dropdown.'=>'Suchen Sie im Dropdown nach einem beliebigen Text auf dieser Seite.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Ihre %s-Lizenz ist <span class="trp-license-status-emphasized">abgelaufen</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Bitte erneuern Sie Ihre Lizenz, um weiterhin Zugriff auf TranslatePress AI, Premium-Addons, automatische Updates und Support zu erhalten.','Renew Now'=>'Jetzt erneuern','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Erneuern Sie Ihre Lizenz an diesem Black Friday zu einem Sonderpreis</strong>, um weiterhin Zugriff auf Produktdownloads, automatische Updates und Support zu erhalten.','Get Deal'=>'Angebot sichern','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Ihre %s-Lizenz wurde <span class="trp-license-status-emphasized">zurückerstattet</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Bitte erwerben Sie eine neue Lizenz, um weiterhin Zugriff auf TranslatePress AI, Premium-Addons, automatische Updates und Support zu erhalten.','Purchase a new license'=>'Neue Lizenz erwerben','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Ihre %s-Lizenz ist <span class="trp-license-status-emphasized">nicht vorhanden oder ungültig</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Bitte geben Sie eine gültige Lizenz ein, um Zugriff auf TranslatePress AI, Premium-Addons, automatische Updates und Support zu erhalten. Benötigen Sie einen Lizenzschlüssel? %1$sErwerben Sie jetzt eine%2$s','Enter a valid license'=>'Gültige Lizenz eingeben','Slugs'=>'Slugs','Meta Information'=>'Meta-Informationen','String List'=>'String-Liste','Gettext Strings'=>'Gettext-Strings','Images'=>'Bilder','Videos'=>'Videos','Audios'=>'Audiodateien','Dynamically Added Strings'=>'Dynamisch hinzugefügte Strings','Translation Editor'=>'Übersetzungseditor','Edit translations by visually selecting them on each site page'=>'Bearbeiten Sie Übersetzungen, indem Sie sie auf jeder Seite der Website visuell auswählen','String Translation'=>'String-Übersetzung','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'URL-Slug-Übersetzungen, Plugin-Übersetzungen und Theme-Übersetzungen bearbeiten (E-Mails, Formulare usw.)','Current User'=>'Aktueller Benutzer','Logged Out'=>'Abgemeldet','Translate Page'=>'Seite übersetzen','Add a New Language'=>'Neue Sprache hinzufügen','Get a Free AI License'=>'Kostenlose AI-Lizenz erhalten','Your License is Invalid'=>'Ihre Lizenz ist ungültig.','Get More AI Words (%d left)'=>'Weitere AI-Wörter erhalten (%d übrig)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Öffnet den Beitrag im Übersetzungseditor. Der Beitrag muss zuvor als Entwurf gespeichert oder veröffentlicht sein.','Security check'=>'Sicherheitsüberprüfung','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Warnung:</strong> Einige Zeichenketten enthalten möglicherweise falsch kodierte Zeichen. Dies kann zu Fehlern bei den Abfragen führen und dazu führen, dass die Seite im Live-Modus nicht übersetzt angezeigt wird. Bitte prüfen Sie die folgenden Zeichenketten oder deren Ausgabemethode.','TranslatePress data update'=>'TranslatePress-Datenaktualisierung','We need to update your translations database to the latest version.'=>'Wir müssen Ihre Übersetzungsdatenbank auf die neueste Version aktualisieren.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Die Aktualisierung ermöglicht die Bearbeitung von Übersetzungen für lokalisierte Texte von Plugins und Theme. Vorhandene Übersetzungen funktionieren weiterhin wie erwartet.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'WICHTIG: Es wird dringend empfohlen, zunächst eine Sicherungskopie der Datenbank anzulegen!
Sind Sie sicher, dass Sie fortfahren möchten?','Run the updater'=>'Updater ausführen','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Das Update ermöglicht die Bearbeitung von Übersetzungen für Slugs. Bestehende Übersetzungen funktionieren weiterhin wie erwartet.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Bitte aktivieren Sie das SEO-Addon im Bereich <br/>WordPress -> Einstellungen -> TranslatePress -> Addons','Go to Addons'=>'Zu den Addons wechseln','The SEO Pack add-on allows translation of all the URL slugs:'=>'Das Add-on SEO Pack ermöglicht die Übersetzung aller URL-Slugs:','Taxonomy slugs'=>'Taxonomie-Slugs','Term slugs'=>'Begriffs-Slugs','Post slugs (this includes pages and custom post types)'=>'Beitrags-Slugs (dies umfasst Seiten und benutzerdefinierte Beitragstypen)','Post type base slugs'=>'Basis-Slugs von Beitragstypen','WooCommerce slugs'=>'WooCommerce-Slugs','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'Das Add-on SEO Pack ist mit ALLEN Premium-Versionen des Plugins verfügbar.','Upgrade to Pro'=>'Auf Pro upgraden','Description'=>'Beschreibung','Article Section'=>'Artikel-Abschnitt','Article Tag'=>'Artikel-Schlagwort','OG Title'=>'OG-Titel','OG Site Name'=>'OG-Seitenname','OG Description'=>'OG-Beschreibung','OG Image Alt'=>'OG-Bild-Alt-Text','Twitter Title'=>'Twitter-Titel','Twitter Description'=>'Twitter-Beschreibung','Twitter Image Alt'=>'Twitter-Bild-Alt-Text','Page Title'=>'Seitentitel','Dublin Core Title'=>'Dublin-Core-Titel','Dublin Core Description'=>'Dublin-Core-Beschreibung','OG Image'=>'OG-Bild','OG Image Secure URL'=>'OG-Bild-Secure-URL','Twitter Image'=>'Twitter-Bild','Removing cdata dictionary strings for language %s...'=>'Entfernen von CDATA-Wörterbuch-Zeichenketten für die Sprache %s...','Removing untranslated dictionary links for language %s...'=>'Entfernen der nicht übersetzten Wörterbuch-Links für die Sprache %s...','Removing duplicated gettext strings for language %s...'=>'Entfernen von doppelten Gettext-Zeichenketten für die Sprache %s...','Removing duplicated dictionary strings for language %s...'=>'Entfernen von doppelten Wörterbuch-Zeichenketten für die Sprache %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Entfernen von unübersetzten Wörterbuch-Zeichenketten mit vorhandener Übersetzung für die Sprache %s...','Inserting original strings for language %s...'=>'Einfügen von Original-Zeichenketten für die Sprache %s...','Cleaning original strings table for language %s...'=>'Bereinigen der Tabelle mit Original-Zeichenketten für die Sprache %s...','Updating original string ids for language %s...'=>'Aktualisieren der Original-Zeichenketten-IDs für die Sprache %s...','Regenerating original meta table for language %s...'=>'Neuerstellen der Meta-Tabelle der Original-Strings für die Sprache %s...','Cleaning original meta table for language %s...'=>'Bereinigen der Meta-Tabelle der Original-Strings für die Sprache %s...','Replacing original id NULL with value for language %s...'=>'Ersetzen der Original-ID NULL durch einen Wert für die Sprache %s...','Inserting gettext original strings for language %s...'=>'Einfügen von Original-Gettext-Zeichenketten für die Sprache %s...','Cleaning gettext original strings table for language %s...'=>'Bereinigen der Tabelle mit Original-Gettext-Zeichenketten für die Sprache %s...','Updating gettext original string ids for language %s...'=>'Aktualisieren der Original-Gettext-Zeichenketten-IDs für die Sprache %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Migrieren von Taxonomie- und Beitragstyp-Basis-Slugs in die neue Tabellenstruktur...','Migrating post slugs to new table structure for language %s...'=>'Migrieren von Beitrags-Slugs in die neue Tabellenstruktur für die Sprache %s...','Migrating term slugs to new table structure for language %s...'=>'Migration der Begriffs-Slugs in die neue Tabellenstruktur für die Sprache %s...','Finishing up...'=>'Abschließen...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Die Datenbankoptimierung wurde nicht erfolgreich abgeschlossen. Wir empfehlen, die Originaldatenbank wiederherzustellen oder <a href="%s" >erneut zu versuchen.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Aktualisierung abgebrochen! Ihr Benutzerkonto verfügt nicht über die erforderlichen Berechtigungen, um Datenbankaktualisierungen durchzuführen.','Update aborted! Invalid nonce.'=>'Aktualisierung abgebrochen! Ungültiger nonce.','Update aborted! Incorrect action.'=>'Aktualisierung abgebrochen! Ungültige Aktion.','Update aborted! Incorrect language code.'=>'Aktualisierung abgebrochen! Falscher Sprachcode.','Updating database to version %s+'=>'Datenbank wird auf Version %s+ aktualisiert...','Processing table for language %s...'=>'Tabelle für Sprache %s wird verarbeitet...','Back to TranslatePress Settings'=>'Zurück zu den TranslatePress-Einstellungen','Successfully updated database!'=>'Datenbank erfolgreich aktualisiert!',' done.'=>' abgeschlossen.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Alle einzelnen TranslatePress-Add-on-Plugins <a href="%1$s" target="_blank">wurden eingestellt</a> und sind nun in den Premium-Versionen Personal, Business und Developer von TranslatePress enthalten. Bitte melden Sie sich auf Ihrer <a href="%2$s" target="_blank">Kontoseite</a> an, laden Sie die neue Premium-Version herunter und installieren Sie diese. Ihre individuellen Add-on-Einstellungen werden übernommen.','Brand-new Language Switcher Settings are here!'=>'Brandneue Sprachumschalter-Einstellungen sind da!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Entdecken Sie vorgefertigte Vorlagen, Farben, Flaggenstile, Abstände, Layouts und mehr. Nutzen Sie die Live-Vorschau, um Ihren Umschalter in Sekundenschnelle zu perfektionieren.','Start customizing'=>'Jetzt anpassen','Read documentation'=>'Dokumentation lesen','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> erfordert die <strong><a href="http://php.net/manual/en/book.mbstring.php">PHP-Bibliothek für Multibyte-Strings</a></strong>. Bitte wenden Sie sich an Ihren Server-Administrator, um diese auf Ihrem Server installieren zu lassen.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Es wurde eine Begrenzung langer Abfragen auf dem WPEngine-Hosting erkannt. Einige große Seiten werden möglicherweise unübersetzt angezeigt. Sie können diese Begrenzung aufheben, indem Sie Folgendes zur wp-config.php Ihrer Website hinzufügen: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Benutzerdefinierte Sprachflagge','The Language code of the added custom language cannot be empty.'=>'Der Sprachcode der hinzugefügten benutzerdefinierten Sprache darf nicht leer sein.','The Language code of the added custom language is invalid.'=>'Der Sprachcode der hinzugefügten benutzerdefinierten Sprache ist ungültig.','The Automatic Translation Code of the added custom language is invalid.'=>'Der Code für die automatische Übersetzung der hinzugefügten benutzerdefinierten Sprache ist ungültig.','TranslatePress Add-ons'=>'TranslatePress-Add-ons','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Sie müssen zunächst diese Version erwerben, um Zugriff auf das Add-on %1$shier%2$s zu erhalten.','Please %1$senter your license%2$s key first, to activate this addon.'=>'Bitte %1$sgeben Sie zuerst Ihren Lizenzschlüssel ein%2$s, um dieses Addon zu aktivieren.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Sie benötigen eine aktive Lizenz, um Zugriff auf das Addon zu haben. Erneuern oder erwerben Sie %1$shier%2$s eine neue.','Advanced Add-ons'=>'Erweiterte Add-ons','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Diese Add-ons erweitern Ihr Übersetzungs-Plugin und sind in den Plänen Developer, Business und Personal verfügbar.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Legacy)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'SEO-Unterstützung für den Seiten-Slug, den Seitentitel, die Beschreibung sowie die Social-Graph-Informationen für Facebook und Twitter. Das HTML-lang-Attribut wird korrekt gesetzt.','Multiple Languages'=>'Mehrere Sprachen','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Fügen Sie Ihrem Projekt so viele Sprachen hinzu, wie Sie benötigen, um global zu werden. Veröffentlichen Sie Ihre Sprache erst, wenn alle Übersetzungen fertig sind.','Pro Add-ons'=>'Pro-Add-ons','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Diese Add-ons erweitern Ihr Übersetzungs-Plugin und sind in den Plänen Business und Developer verfügbar.','DeepL Automatic Translation'=>'Automatische DeepL-Übersetzung','Automatically translate your website through the DeepL API.'=>'Übersetzen Sie Ihre Website automatisch über die DeepL-API.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Fordert Besucher auf, basierend auf ihren Browsereinstellungen oder ihrer IP-Adresse in ihre bevorzugte Sprache zu wechseln, und speichert die zuletzt besuchte Sprache.','Translator Accounts'=>'Übersetzerkonten','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Erstellen Sie Übersetzerkonten für neue Benutzer oder erlauben Sie bestehenden Benutzern ohne Administratorrechte, Ihre Website zu übersetzen.','Browse As User Role'=>'Als Benutzerrolle durchsuchen','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Navigieren Sie durch Ihre Website, wie eine bestimmte Benutzerrolle es tun würde. Sehr nützlich für dynamische Inhalte oder versteckte Inhalte, die für bestimmte Benutzer angezeigt werden.','Navigation Based on Language'=>'Sprachbasierte Navigation','Configure different menu items for different languages.'=>'Konfigurieren Sie unterschiedliche Menüpunkte für verschiedene Sprachen.','Different Domain per Language'=>'Unterschiedliche Domain pro Sprache','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Verbinden Sie separate Domains oder Subdomains mit jeder Ihrer übersetzten Versionen. Stärken Sie die lokale Identität Ihrer Marke und verbessern Sie die SEO-Leistung für jede Sprache, die Sie unterstützen.','Recommended Plugins'=>'Empfohlene Plugins','A short list of plugins you can use to extend your website.'=>'Eine kurze Liste von Plugins, die Sie zur Erweiterung Ihrer Website verwenden können.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Erfassen Sie mehr Benutzerinformationen im Registrierungsformular mithilfe der benutzerdefinierten Benutzerprofilfelder von Profile Builder und/oder fügen Sie einen Prozess zur E-Mail-Bestätigung hinzu, um die Konten Ihrer Kunden zu verifizieren.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Nehmen Sie Zahlungen von Benutzern entgegen, erstellen Sie Abonnementpläne und beschränken Sie Inhalte auf Ihrer Mitgliedschaftswebsite.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Erstellen Sie No-Code-Automatisierungen und Workflows auf Ihrer WordPress-Website. Verbinden Sie Ihre Plugins, Websites und Apps ganz einfach miteinander.','Save Changes'=>'Änderungen speichern','TranslatePress Errors'=>'TranslatePress-Fehler','There are no logged errors.'=>'Es wurden keine Fehler protokolliert.','Change language'=>'Sprache ändern','Website language selector'=>'Sprachauswahl der Website','WordPress Translation Plugin'=>'WordPress-Übersetzungsplugin','Available languages'=>'Verfügbare Sprachen','Language Switcher update notice'=>'Hinweis zur Aktualisierung der Sprachauswahl','Legacy language switcher is currently enabled'=>'Die Legacy-Sprachauswahl ist derzeit aktiviert.','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Wir haben die Sprachauswahl für umfangreichere Anpassungsmöglichkeiten und eine bessere Benutzererfahrung aktualisiert.<br>Um den neuen Konfigurator zu verwenden, deaktivieren Sie <strong>Legacy-Sprachauswahl laden</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Hinweis: Sie können jederzeit über <strong>Erweiterte Einstellungen → <a href="%s">Fehlerbehebung</a></strong> zurückwechseln.','Enable the new switcher'=>'Neuen Switcher aktivieren','Your License Key is valid.'=>'Ihr Lizenzschlüssel ist gültig.','Your License Key is invalid.'=>'Ihr Lizenzschlüssel ist ungültig.','Your License has expired.'=>'Ihre Lizenz ist abgelaufen.','Deactivate License'=>'Lizenz deaktivieren','Add a license key'=>'Lizenzschlüssel hinzufügen','License Key'=>'Lizenzschlüssel','Manage your license in your %1$s.'=>'Verwalten Sie Ihre Lizenz auf Ihrer %1$s.','Account Page'=>'Kontoseite','Don’t have a TranslatePress AI License Key?'=>'Haben Sie keinen TranslatePress AI-Lizenzschlüssel?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Sie können einen %1$skostenlos%2$s erhalten, indem Sie ein kostenloses Konto erstellen. Folgendes ist enthalten:','Access to TranslatePress AI for instant automatic translations'=>'Zugriff auf TranslatePress AI für sofortige automatische Übersetzungen','2000 AI words to translate automatically'=>'2000 Wörter zur automatischen Übersetzung','Get a free License Today'=>'Heute eine kostenlose Lizenz erhalten','Debug Information'=>'Debug-Informationen','Debug Data for License Checking'=>'Debug-Daten für die Lizenzprüfung','Debug Data for License Activation'=>'Debug-Daten für die Lizenzaktivierung','Get more AI words and unlock all features with TranslatePress Pro.'=>'Erhalten Sie mehr Wörter für automatische Übersetzungen und schalten Sie alle Funktionen mit TranslatePress Pro frei.','Upgrade now ↗'=>'Jetzt upgraden ↗','Already purchased a Premium version?'=>'Haben Sie bereits eine Premium-Version erworben?','Go to your %1$s'=>'Gehen Sie zu Ihrem %1$s','TranslatePress.com Account'=>'TranslatePress.com-Konto','Download & Install the Pro plugin'=>'Pro-Plugin herunterladen und installieren','Learn More'=>'Mehr erfahren','Get a translation volume estimate with a detailed breakdown per page'=>'Eine Schätzung des Übersetzungsvolumens mit detaillierter Aufschlüsselung pro Seite erhalten','Find how many translatable words are on your website'=>'Ermitteln, wie viele übersetzbare Wörter auf Ihrer Website vorhanden sind','Enable Automatic Translation'=>'Automatische Übersetzung aktivieren','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Um <strong>DeepL</strong> für die automatische Übersetzung zu verwenden, aktivieren Sie dieses Pro-Add-on unter <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Die automatische Übersetzung mit <strong>DeepL</strong> ist als <a href="%1$s" target="_blank" title="%2$s">%2$s</a> verfügbar.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Mit einem Upgrade erhalten Sie Zugriff auf alle kostenpflichtigen Add-ons und den Premium-Support und helfen mit, die zukünftige Entwicklung von TranslatePress zu finanzieren.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Bitte beachten Sie, dass die Nutzung der DeepL API separat bezahlt wird. Siehe <a href="https://www.deepl.com/pro.html#developer">DeepL-Preisinformationen</a>.','TranslatePress Pro Add-ons'=>'TranslatePress Pro Add-ons','Test API credentials'=>'API-Zugangsdaten testen','Check if the selected translation engine is configured correctly.'=>'Prüfen Sie, ob die ausgewählte Übersetzungs-Engine korrekt konfiguriert ist.','Alternative Engines'=>'Alternative Engines','Switch to TranslatePress AI'=>'Zu TranslatePress AI wechseln','Integrate machine translation directly with your WordPress website.'=>'Integrieren Sie die maschinelle Übersetzung direkt in Ihre WordPress-Website.','More info'=>'Weitere Informationen','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Wählen Sie aus, welche Engine Sie verwenden möchten, um %1$s Ihre Website automatisch zu übersetzen.','Automatic Translation Settings'=>'Einstellungen für automatische Übersetzung','AI Words Low Notification'=>'Benachrichtigung bei niedrigem AI-Wörterbestand','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Sie erhalten eine E-Mail-Benachrichtigung, wenn Ihr TranslatePress AI-Wörterbestand unter den angegebenen Schwellenwert fällt.','This feature is only available when using the TranslatePress AI translation engine.'=>'Diese Funktion ist nur verfügbar, wenn Sie die TranslatePress AI-Übersetzungsmaschine verwenden.','Notification Email'=>'Benachrichtigungs-E-Mail','The email address where the low AI words notification will be sent.'=>'Die E-Mail-Adresse, an die die Benachrichtigung bei niedrigem AI-Wörterbestand gesendet wird.','Word Threshold'=>'Schwellenwert','words'=>'Wörter','You will be notified when remaining AI words drop below this number.'=>'Sie werden benachrichtigt, wenn die verbleibenden AI-Wörter unter diese Zahl fallen.','Automatically Translate Slugs'=>'Slugs automatisch übersetzen','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Generiert automatische Übersetzungen von Slugs für Beiträge, Seiten und Custom Post Types.<br/>Die Slugs werden ab der zweiten Aktualisierung jeder Seite automatisch übersetzt.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Diese Funktion ist nur in der kostenpflichtigen Version verfügbar. Upgraden Sie TranslatePress und schalten Sie weitere Premium-Funktionen frei.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Erfordert die Installation und Aktivierung von <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a>.','Upgrade now'=>'Jetzt upgraden','Block Crawlers'=>'Crawler blockieren','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Verhindert, dass Crawler automatische Übersetzungen auf Ihrer Website auslösen.<br>Dies verhindert nicht, dass Crawler auf die Seiten dieser Website zugreifen.','Limit machine translation / characters per day'=>'Maschinelle Übersetzung / Zeichen pro Tag begrenzen','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Legen Sie eine Begrenzung für die Anzahl automatisch übersetzter Zeichen fest, um Ihr Projekt besser zu planen.','characters per day'=>'Zeichen pro Tag','Today\'s Character Count: '=>'Heutige Zeichenanzahl: ','Log machine translation queries.'=>'Maschinelle Übersetzungsanfragen protokollieren.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Nur zu Testzwecken aktivieren. Kann die Leistung beeinträchtigen.<br>Alle Datensätze werden in der Datenbanktabelle wp_trp_machine_translation_log gespeichert. Verwenden Sie ein Plugin wie <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a>, um die Protokolle zu durchsuchen, oder direkt über Ihren Datenbankmanager (PHPMyAdmin, etc.).','Test API Credentials'=>'API-Zugangsdaten testen','HTTP Referrer: '=>'HTTP Referrer: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Verwenden Sie diesen HTTP Referrer, wenn die API es Ihnen ermöglicht, die Schlüsselnutzung über ihr Dashboard einzuschränken.','Response'=>'Antwort','Response Body'=>'Antworttext','Entire Response From wp_remote_get():'=>'Vollständige Antwort von wp_remote_get():','All Languages'=>'Alle Sprachen','Select the languages you wish to make your website available in.'=>'Wählen Sie die Sprachen aus, in denen Ihre Website verfügbar sein soll.','Formality'=>'Formalebene','Code'=>'Code','Slug'=>'Slug','Default'=>'Standard','Formal'=>'Formell','Informal'=>'Informell','Language'=>'Sprache','This language does not support formality. '=>'Diese Sprache unterstützt keine Formalebene. ','Are you sure you want to remove this language?'=>'Sind Sie sicher, dass Sie diese Sprache entfernen möchten?','Custom Languages'=>'Benutzerdefinierte Sprachen','To Add more languages activate the Multiple Languages Addon'=>'Um weitere Sprachen hinzuzufügen, aktivieren Sie das Multiple Languages Addon.','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Sie benötigen eine aktive Lizenz, um weitere Sprachen hinzuzufügen. Überprüfen Sie in Ihrem %1$sKonto%2$s, ob Ihre Lizenz gültig ist.','Please %1$senter your license%2$s key first to add more languages.'=>'Bitte %1$sgeben Sie zunächst Ihren Lizenzschlüssel%2$s ein, um weitere Sprachen hinzuzufügen.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Das Hinzufügen von mehr als zwei Sprachen ist eine kostenpflichtige Funktion. Führen Sie ein Upgrade für TranslatePress durch und schalten Sie weitere Premium-Funktionen frei.','Website Languages'=>'Website-Sprachen','Default Language'=>'Standardsprache','Select the language your content is written in.'=>'Wählen Sie die Sprache aus, in der Ihre Inhalte verfasst sind.','WARNING. Changing the default language will invalidate existing translations.'=>'WARNUNG. Das Ändern der Standardsprache macht vorhandene Übersetzungen ungültig.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Selbst ein Wechsel von en_US zu en_GB, da diese als zwei verschiedene Sprachen behandelt werden.','In most cases changing the default flag is all it is needed: '=>'In den meisten Fällen ist das Ändern der Standard-Flagge alles, was benötigt wird: ','replace the default flag'=>'die Standard-Flagge ersetzen','Re-run Setup Wizard'=>'Setup-Assistenten erneut ausführen','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Der Setup-Assistent ermöglicht es Ihnen, TranslatePress schnell einzurichten. Sie können ihn jederzeit starten.','Language Settings'=>'Spracheinstellungen','Use Native language name'=>'Nativen Sprachnamen verwenden','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Aktivieren Sie diese Option, wenn Sie Sprachen in ihren nativen Namen anzeigen möchten. Andernfalls werden Sprachen auf Englisch angezeigt.','Use a subdirectory for the default language'=>'Unterverzeichnis für die Standardsprache verwenden','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Aktivieren Sie diese Option, wenn Sie das Unterverzeichnis in der URL für die Standardsprache hinzufügen möchten.</br>Wenn Sie diese Option aktivieren, wird die von Website-Besuchern angezeigte Standardsprache zur ersten in der Liste „Alle Sprachen“.','Force language in custom links'=>'Sprache in benutzerdefinierten Links erzwingen','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Wählen Sie „Ja“, wenn Sie möchten, dass benutzerdefinierte Links ohne Sprachkodierung die aktuell ausgewählte Sprache beibehalten.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Verwenden Sie shortcode auf einer beliebigen Seite oder in einem Widget.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Sie können den <a href="%s" title="Language Switcher Block Documentation">Sprachwechsler-Block</a> auch im WP Gutenberg Editor hinzufügen.','Menu item'=>'Menüpunkt','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Gehen Sie zu  %1$s Design -> Menüs%2$s und fügen Sie in einem beliebigen Menü Sprachen zum Sprachwechsler hinzu.','Learn more in our documentation.'=>'Erfahren Sie mehr in unserer Dokumentation.','Floating language selection'=>'Schwebende Sprachauswahl','Add a floating dropdown that follows the user on every page.'=>'Fügen Sie ein schwebendes Dropdown hinzu, das dem Benutzer auf jeder Seite folgt.','Show "Powered by TranslatePress"'=>'"Powered by TranslatePress" anzeigen','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Das kleine Label "Powered by TranslatePress" im schwebenden Sprachumschalter anzeigen.','5 Days to Better Multilingual Websites'=>'5 Tage zu besseren mehrsprachigen Websites','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sNehmen Sie an unserem KOSTENLOSEN und EXKLUSIVEN Onboarding-Kurs teil%s und erfahren Sie, wie Sie Ihren mehrsprachigen Traffic steigern, internationale Märkte erreichen und Zeit und Geld sparen, während Sie das Maximum aus TranslatePress herausholen!','Invalid email address'=>'Ungültige E-Mail-Adresse','Your email'=>'Ihre E-Mail-Adresse','Sign me up!'=>'Anmelden!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Melden Sie sich mit Ihrer E-Mail-Adresse an und erhalten Sie einen 5-teiligen E-Mail-Leitfaden, der Ihnen hilft, das volle Potenzial von TranslatePress auszuschöpfen.','Dismiss email course notification'=>'Benachrichtigung zum E-Mail-Kurs schließen','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Hallo %s,<br>Verpassen Sie keine wichtige Aktualisierung - melden Sie sich für Benachrichtigungen zu Sicherheits- und Funktionsaktualisierungen sowie für nicht sensibles Diagnose-Tracking an.','Allow & Continue'=>'Zulassen und Fortfahren','Skip'=>'Überspringen','This will allow TranslatePress to:'=>'Dies ermöglicht TranslatePress Folgendes:','Your profile overview'=>'Profilübersicht','Name and email address'=>'Name und E-Mail-Adresse','Admin Notices'=>'Admin-Hinweise','Updates, announcements, marketing, no spam'=>'Updates, Ankündigungen, Marketing, kein Spam','Plugin status & settings'=>'Plugin-Status und Einstellungen','Active, Deactivated, installed version and settings'=>'Aktiv, Deaktiviert, installierte Version und Einstellungen','Privacy Policy'=>'Datenschutzerklärung','Terms of Service'=>'Nutzungsbedingungen','Support'=>'Support','Documentation'=>'Dokumentation','Add Extra AI Words'=>'Zusätzliche AI-Wörter hinzufügen','Optimize TranslatePress database tables'=>'TranslatePress-Datenbanktabellen optimieren','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>WICHTIGER HINWEIS:</strong> Es wird dringend empfohlen, vor dem Ausführen dieser Aktion zunächst eine Sicherung der Datenbank zu erstellen.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'WICHTIG: Es wird dringend empfohlen, zunächst eine Sicherung der Datenbank zu erstellen!! Sind Sie sicher, dass Sie fortfahren möchten?','Operations to perform'=>'Auszuführende Operationen','Remove CDATA for original and dictionary strings'=>'CDATA für Original- und Dictionary-Strings entfernen','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Entfernt CDATA aus den Tabellen trp_original_strings und trp_dictionary_*.<br>Dieser Inhaltstyp sollte von TranslatePress nicht erkannt werden. Er könnte in älteren Versionen des Plugins in die Datenbank eingefügt worden sein.','Remove untranslated links from dictionary tables'=>'Unübersetzte Links aus Wörterbuch-Tabellen entfernen','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Entfernt nicht übersetzte Links und Bilder aus allen trp_dictionary_*-Tabellen. Diese Tabellen enthalten Übersetzungen für benutzereingegebene Strings wie Beitragsinhalt, Beitragstitel, Menüs usw.','Remove duplicate rows for gettext strings'=>'Doppelte Zeilen für Gettext-Strings entfernen','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Bereinigt alle trp_gettext_*-Tabellen von doppelten Zeilen. Diese Tabellen enthalten Übersetzungen für Theme- und Plugin-Strings.','Remove duplicate rows for dictionary strings'=>'Doppelte Zeilen für Dictionary-Strings entfernen','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Bereinigt alle trp_dictionary_*-Tabellen von doppelten Zeilen. Diese Tabellen enthalten Übersetzungen für benutzereingegebene Strings wie Beitragsinhalt, Beitragstitel, Menüs usw.','Remove duplicate rows for original dictionary strings'=>'Doppelte Zeilen für Original-Dictionary-Strings entfernen','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Bereinigt die Tabelle trp_original_strings von doppelten Zeilen. Diese Tabelle enthält Strings in der Standardsprache ohne jegliche Übersetzung.<br>Die Tabelle trp_original_meta, die Meta-Informationen mit Bezug zur ID des übergeordneten Beitrags enthält, wird ebenfalls neu generiert.<br>Solche Duplikate können in Ausnahmesituationen bei unerwartetem Verhalten auftreten.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Gettext-Strings, deren Original-ID NULL ist, durch die korrekten Original-IDs ersetzen','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Behebt ein Randfall-Problem, bei dem bei einigen Gettext-Strings die Original-ID fälschlicherweise auf NULL gesetzt ist, was Probleme im Übersetzungs-Editor verursacht.<br>Dieser Vorgang korrigiert die Original-IDs in den trp_gettext_*-Tabellen.<br>Aktivieren Sie diese Option nur, wenn Sie im Übersetzungs-Editor auf ein Problem gestoßen sind, bei dem ein Klick auf den grünen Stift den Gettext-String nicht zur Übersetzung in der linken Seitenleiste angezeigt hat.<br>Anderenfalls lassen Sie diese Option bitte deaktiviert, da dies ein intensiver Vorgang ist.','Optimize Database'=>'Datenbank optimieren','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'TranslatePress-Tabellen werden aktualisiert. Bitte lassen Sie dieses Fenster geöffnet.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Die inaktiven Sprachen sind für den Administrator weiterhin sichtbar und aktiv. Für andere Benutzer sind sie in den Sprachumschaltern nicht sichtbar und auch nicht zugänglich.','unknown'=>'Unbekannt','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Extra Languages Add-on</strong> erfordert TranslatePress in der Version %1$s oder höher. Sie verwenden derzeit Version %2$s. Bitte aktualisieren Sie TranslatePress, um diese Funktion zu aktivieren.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Automatische und manuelle Slug-Übersetzungsänderungen, die durchgeführt wurden, während <strong>TranslatePress - Multilingual</strong> 2.8.4 aktiv war, mussten aufgrund einiger Probleme mit dieser Version entfernt werden. Alle Slug-Übersetzungen aus der Zeit vor dieser Version sind nun wieder aktiv. Vielen Dank für Ihr Verständnis!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Falls Sie diese unbedingt benötigen, befinden sich die entfernten Übersetzungen in den Tabellen trp_slug_original_obsolete und trp_slug_translation_obsolete.','View Docs'=>'Dokumentation anzeigen','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Weisen Sie jeder Sprache unterschiedliche Domains oder Subdomains zu. Wenn Besucher diese Domains aufrufen, lädt TranslatePress die entsprechende Sprachübersetzung direkt, ohne Weiterleitung.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Beispiel: %1$s für Englisch, %2$s für Spanisch, %3$s für Französisch.','Before enabling:'=>'Vor der Aktivierung:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Stellen Sie sicher, dass Ihre Domains registriert, auf Ihren Server verweisen und SSL-Zertifikate konfiguriert sind.','Domain'=>'Domain','Map this language to a different domain or sub-domain.'=>'Ordnen Sie diese Sprache einer anderen Domain oder Subdomain zu.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Mit aktueller Domain vorausfüllen','Check DNS'=>'DNS prüfen','Checking DNS...'=>'DNS wird geprüft...','DNS is correctly configured!'=>'DNS ist korrekt konfiguriert!','DNS check failed. Please verify your domain configuration.'=>'DNS-Prüfung fehlgeschlagen. Bitte überprüfen Sie Ihre Domain-Konfiguration.','This domain is already assigned to another language.'=>'Diese Domain ist bereits einer anderen Sprache zugeordnet.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Erweiterung für unterschiedliche Domains pro Sprache</strong> erfordert TranslatePress-Version %1$s oder höher. Sie verwenden derzeit Version %2$s. Bitte aktualisieren Sie TranslatePress, um diese Funktion zu aktivieren.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Hinweis: Diese Option ist deaktiviert, wenn die Erweiterung für unterschiedliche Domains pro Sprache aktiv ist.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Unterschiedliche Domain pro Sprache: Eine Domain ist erforderlich, wenn Domain-Mapping aktiviert ist. Der Schalter wurde für Sprachen mit leeren Domains deaktiviert.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Unterschiedliche Domain pro Sprache: Dieselbe Domain kann nicht mehreren Sprachen zugeordnet werden. Der Schalter wurde für doppelte Domains deaktiviert.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Unterschiedliche Domain pro Sprache: Eine Sprach-Domain darf nicht mit der Haupt-URL der Website identisch sein. Der Schalter wurde für die übereinstimmende Domain deaktiviert.','Please enter a domain.'=>'Bitte geben Sie eine Domain ein.','Invalid domain format.'=>'Ungültiges Domain-Format.','Could not reach domain: %s'=>'Die Domain konnte nicht erreicht werden: %s','Domain returned HTTP status %d.'=>'Die Domain hat den HTTP-Status %d zurückgegeben.','Domain is reachable!'=>'Die Domain ist erreichbar!','Limit this menu item to the following languages'=>'Diesen Menüpunkt auf die folgenden Sprachen beschränken','Date format'=>'Datumsformat','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Passen Sie die Datumsformatierung für jede übersetzte Sprache an.<br/>Leer lassen für die standardmäßige WP-Einstellung oder weitere Informationen <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">hier</a> einsehen','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Um eine vorhandene TranslatePress-Sprache zu bearbeiten, geben Sie den Sprachcode ein und füllen Sie nur die Spalten aus, die Sie überschreiben möchten (z. B. Sprachname, Flagge).<br>Sie können auch neue benutzerdefinierte Sprachen hinzufügen. Diese werden unter Allgemeine Einstellungen in der Liste aller Sprachen verfügbar sein, wo der URL-Slug bearbeitet werden kann.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Für eine benutzerdefinierte Flagge laden Sie zunächst das Bild in die Mediathek hoch und fügen Sie dann die URL ein.<br>Das Ändern oder Löschen einer benutzerdefinierten Sprache wirkt sich auf Übersetzungen und Website-URLs aus.<br>Der Sprachcode und der ISO-Code sollten nur alphabetische Werte, numerische Werte, „-“ und „_“ enthalten.<br>Die ISO-Codes finden Sie unter <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> und <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.','Language code'=>'Sprachcode','Language name'=>'Sprachname','Native name'=>'Nativer Name','ISO Code'=>'ISO-Code','Flag URL'=>'Flaggen-URL','Text RTL'=>'Text RTL','Custom language'=>'Benutzerdefinierte Sprache','Disable dynamic translation'=>'Dynamische Übersetzung deaktivieren','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Es deaktiviert die Erkennung von Strings, die dynamisch per JavaScript angezeigt werden. <br/>Strings, die über einen serverseitigen AJAX-Aufruf geladen werden, werden weiterhin übersetzt.','Disable translation for gettext strings'=>'Übersetzung für Gettext-Strings deaktivieren','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Gettext-Zeichenketten werden von Themes und Plugins ausgegeben. <br> Die Übersetzung dieser Arten von Zeichenketten über TranslatePress kann unnötig sein, wenn sie bereits über das .po/.mo-Übersetzungsdateisystem übersetzt wurden.<br>Das Aktivieren dieser Option kann in bestimmten Fällen die Ladegeschwindigkeit Ihrer Website verbessern. Der Nachteil ist, dass Sie Gettext-Übersetzungen nicht mehr mit TranslatePress bearbeiten können und auch nicht mehr von der automatischen Übersetzung dieser Zeichenketten profitieren.','Gettext Strings translation is disabled'=>'Die Übersetzung von Gettext-Zeichenketten ist deaktiviert','To enable it go to '=>'Um sie zu aktivieren, gehen Sie zu ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Erweiterte Einstellungen->Debug->Übersetzung für Gettext-Zeichenketten deaktivieren',' and uncheck the Checkbox.'=>' und deaktivieren Sie das Kontrollkästchen.','Dismiss'=>'Verwerfen','Exclude translated links from sitemap'=>'Übersetzte Links aus sitemap ausschließen','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Übersetzte Links nicht in Sitemaps aufnehmen, die von SEO-Plugins generiert werden.<br/>Setzt voraus, dass das <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="Dokumentation für das TranslatePress Add-on SEO Pack" target="_blank"> SEO Pack Add-on</a> installiert und aktiviert ist.','Disable post container tags for post title'=>'Container-Tags für den Beitragstitel deaktivieren','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Dadurch wird die Suchindexierung des Beitragstitels in übersetzten Sprachen deaktiviert.<br/>Nützlich, wenn der Titel des Beitrags kein HTML zulässt, wodurch die Seite zerstört wird.','Disable post container tags for post content'=>'Container-Tags für den Beitragsinhalt deaktivieren','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Dadurch wird die Suchindexierung des Beitragsinhalts in übersetzten Sprachen deaktiviert.<br/>Nützlich, wenn der Inhalt des Beitrags kein HTML zulässt, wodurch die Seite zerstört wird.','Do not translate certain paths'=>'Bestimmte Pfade nicht übersetzen','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Wählen Sie aus, welche Pfade übersetzt werden können. Unterstützt Platzhalter am Ende des Pfads.<br>Um beispielsweise https://example.com/some/path auszuschließen, können Sie entweder die Regel /some/path/ oder /some/* verwenden.<br>Geben Sie jede Regel in eine eigene Zeile ein. Um die Startseite auszuschließen, verwenden Sie {home}.','Exclude Paths From Translation'=>'Pfade von der Übersetzung ausschließen','Translate Only Certain Paths'=>'Nur bestimmte Pfade übersetzen','Enable the hreflang x-default tag for language:'=>'Das hreflang-x-default-Tag für die Sprache aktivieren:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Aktiviert hreflang="x-default" für eine gesamte Sprache. Weitere Details finden Sie in der Dokumentation.','Translate numbers and numerals'=>'Zahlen und Ziffern übersetzen','Enable translation of numbers ( e.g. phone numbers)'=>'Übersetzung von Zahlen aktivieren (z. B. Telefonnummern)','Selector'=>'Selektor','Exclude from dynamic translation'=>'Von der dynamischen Übersetzung ausschließen','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Zeichenketten, die in HTML-Knoten gefunden werden, die diesen Selektoren entsprechen, nicht dynamisch übersetzen.<br>Schließt alle untergeordneten Elemente von HTML-Knoten, die diesen Selektoren entsprechen, von der Übersetzung mit JavaScript aus.<br/>Diese Zeichenketten werden nach Möglichkeit weiterhin serverseitig übersetzt.','Gettext String'=>'Gettext-Zeichenkette','Exclude Gettext Strings'=>'Gettext-Zeichenketten ausschließen','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Diese Zeichenketten von der Übersetzung als Gettext-Zeichenketten durch TranslatePress ausschließen. Lassen Sie die Domain leer, um jede Gettext-Zeichenkette zu berücksichtigen.<br/>Können weiterhin über po/mo-Dateien übersetzt werden.','Exclude selectors only from automatic translation'=>'Selektoren nur von der automatischen Übersetzung ausschließen','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Zeichenketten, die in HTML-Knoten gefunden werden, die diesen Selektoren entsprechen, nicht automatisch übersetzen.<br>Schließt alle untergeordneten Elemente von HTML-Knoten, die diesen Selektoren entsprechen, von der automatischen Übersetzung aus.<br>Die manuelle Übersetzung dieser Zeichenketten ist weiterhin möglich.','Exclude selectors from translation'=>'Selektoren von der Übersetzung ausschließen','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Zeichenketten, die in HTML-Knoten gefunden werden, die diesen Selektoren entsprechen, nicht übersetzen.<br>Schließt alle untergeordneten Elemente von HTML-Knoten, die diesen Selektoren entsprechen, von der Übersetzung aus.<br>Diese Zeichenketten können weder manuell noch automatisch übersetzt werden.','String'=>'Zeichenkette','Exclude strings from automatic translation'=>'Zeichenketten von der automatischen Übersetzung ausschließen','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Diese Zeichenketten nicht automatisch übersetzen (z. B. Namen, Fachbegriffe...)<br>Absätze, die diese Zeichenketten enthalten, werden weiterhin übersetzt, mit Ausnahme des angegebenen Teils.','Fix broken HTML'=>'Fehlerhaftes HTML korrigieren','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Allgemeiner Versuch, fehlerhaftes oder fehlendes HTML auf übersetzten Seiten zu korrigieren.<br/>','Force slash at end of home url:'=>'Schrägstrich am Ende der Home-URL erzwingen:','Ads a slash at the end of the home_url() function'=>'Fügt der home_url()-Funktion einen Schrägstrich am Ende hinzu','Show Both (recommended)'=>'Beide anzeigen (empfohlen)','Remove Country Locale'=>'Länder-Locale entfernen','Remove Region Independent Locale'=>'Regionsunabhängiges Locale entfernen','Remove duplicate hreflang'=>'Doppelte hreflang entfernen','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Wählen Sie aus, welche hreflang-Tags auf Ihrer Website angezeigt werden.<br/>Wir empfehlen, beide Arten von hreflang-Tags anzuzeigen, wie in der <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google-Dokumentation</a> angegeben.<br/>Das Entfernen der Länderkennung bei Vorhandensein mehrerer Länderkennungen derselben Sprache (z. B. Englisch UK und Englisch US) führt dazu, dass nur ein hreflang-Tag mit einem Link zu nur einer der regionalen Sprachversionen für diese Sprache angezeigt wird.','Default (example: en-US, fr-CA, etc.)'=>'Standard (Beispiel: en-US, fr-CA usw.)','Regional (example: en, fr, es, etc.)'=>'Regional (Beispiel: en, fr, es usw.)','HTML Lang Attribute Format'=>'Format des HTML-Lang-Attributs','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Ändern Sie das lang-Attribut des HTML-Tags in ein Format mit oder ohne Länderangabe. <br>In HTML sollte das lang-Attribut (<html lang="en-US">) verwendet werden, um die Sprache des Textinhalts anzugeben, damit der Browser Ihren Inhalt korrekt anzeigen oder verarbeiten kann (z. B. für Silbentrennung, Styling, Rechtschreibprüfung usw.).','Load legacy Language Switcher'=>'Legacy-Sprachumschalter laden','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Gilt für alle Arten von Sprachumschaltern (schwebend, shortcode und Menü). Wenn aktiviert, kehrt die Website zur Verwendung des ursprünglichen Sprachumschalters zurück, der auf der Registerkarte „Allgemeine Einstellungen“ konfiguriert wurde, und ersetzt die neue anpassbare Version. Ihre vorhandenen Umschaltereinstellungen bleiben gespeichert, werden jedoch ignoriert, solange diese Option aktiv ist.','Load legacy SEO Pack Add-On'=>'Legacy-Add-On „SEO Pack“ laden','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Falls die jüngste Migration zum neuen slug-Rewrite Probleme verursacht, setzen Sie dies auf Ja, um die alte Methode zu verwenden.<br> Bitte <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">eröffnen Sie ein Support-Ticket</a>, um uns die Probleme mitzuteilen, die Sie haben.','Manual Translation Only'=>'Nur manuelle Übersetzung','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress scannt und speichert Zeichenketten proaktiv in der Datenbank, wenn Benutzer übersetzte Seiten aufrufen. <br>Diese Einstellung deaktiviert diese Funktion und erlaubt die Übersetzung und das Speichern von Zeichenketten nur innerhalb des Übersetzungs-Editors. <br>Zudem wird die maschinelle Übersetzung außerhalb des Übersetzungs-Editors deaktiviert, wodurch Sie die Kontrolle über den Zeichenverbrauch verbessern, indem nur die Seiten übersetzt werden, die Sie im Übersetzungs-Editor besuchen.','Open language switcher only on click'=>'Sprachumschalter nur per Klick öffnen','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Öffnen Sie den shortcode-Sprachumschalter durch Anklicken anstatt durch Darüberfahren. <br>Schließen Sie ihn durch Anklicken, durch Klicken an eine beliebige andere Stelle auf dem Bildschirm oder durch Drücken der Escape-Taste. Dies betrifft nur den shortcode-Sprachumschalter.','Show opposite language in the language switcher'=>'Andere Sprache im Sprachumschalter anzeigen','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Verwandelt den Sprachumschalter in eine Schaltfläche, die die andere verfügbare Sprache anzeigt, nicht die aktuelle. <br>Funktioniert nur, wenn genau zwei Sprachen vorhanden sind: die Standardsprache und eine Übersetzungssprache. <br>Dies betrifft auch den shortcode-Sprachumschalter und den schwebenden Sprachumschalter. <br>Um dies im Menü-Sprachumschalter zu erreichen, gehen Sie zu Design -> Menüs -> Sprachumschalter und wählen Sie „Andere Sprache“.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Klicken Sie hier</a>, um das Datenbank-Optimierungstool aufzurufen.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Es hilft dabei, mögliche doppelte Übersetzungen zu entfernen, unnötige Daten zu bereinigen und mögliche Metadaten-Probleme zu beheben.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Hier</a> können Sie die letzten 5 SQL-Fehler einsehen, die TranslatePress betreffen, sofern vorhanden.','Troubleshooting'=>'Fehlerbehebung','Exclude Gettext strings'=>'Gettext-Zeichenketten ausschließen','Debug'=>'Debug','Custom languages'=>'Benutzerdefinierte Sprachen','Miscellaneous options'=>'Sonstige Optionen','Exclude strings & pages'=>'Zeichenketten und Seiten ausschließen','Automatic Translation Memory'=>'Automatischer Übersetzungsspeicher','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Dieselbe Übersetzung für ähnliche Texte verwenden. Die Zeichenketten müssen einen Ähnlichkeitsgrad von 95 % aufweisen.<br>Hilft, vorhandene Übersetzungen beim Korrigieren von Tippfehlern oder bei kleineren Anpassungen des Originaltextes nicht zu verlieren. <br>Wenn bereits eine Übersetzung für eine sehr ähnliche Originalzeichenkette existiert, wird diese automatisch für die aktuelle Originalzeichenkette verwendet.<br>Funktioniert nicht, wenn Änderungen an einem Text vorgenommen werden, der Teil eines Übersetzungsblocks ist, es sei denn, der neue Text wird manuell erneut in einen Übersetzungsblock zusammengeführt.<br>Jede Zeichenkette muss mindestens 50 Zeichen umfassen.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'WARNUNG: Diese Funktion kann die Seitenladezeiten in sekundären Sprachen negativ beeinflussen, insbesondere bei großen Datenbanken (zum Beispiel Websites mit vielen Seiten oder Produkten). Falls Sie langsame Ladezeiten feststellen, deaktivieren Sie diese Funktion und versuchen Sie es erneut.','Fix missing dynamic content'=>'Fehlende dynamische Inhalte beheben','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Kann helfen, fehlende Inhalte zu beheben, die mit JavaScript eingefügt wurden. <br> Zeigt dynamisch eingefügte Inhalte kurzzeitig in der Originalsprache an, bevor die Übersetzungsanfrage abgeschlossen ist.','Filter Gettext wrapping from post content and title'=>'Gettext-Umschließung aus Beitragsinhalt und -titel filtern','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtert Gettext-Umschließungen wie #!trpst#trp-gettext aus allen aktualisierten Beitragsinhalten und -titeln. Vorherige Beitragsinhalte bleiben unberührt. <br/><strong>Ein Datenbank-Backup wird vor dem Aktivieren empfohlen.</strong>','Filter Gettext wrapping from post meta'=>'Gettext-Umschließung aus Beitrags-Metadaten filtern','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtert Gettext-Umschließungen wie #!trpst#trp-gettext aus allen aktualisierten Beitrags-Metadaten. Vorherige Beitrags-Metadaten bleiben unberührt. <br/><strong>Ein Datenbank-Backup wird vor dem Aktivieren empfohlen.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Google Translate API-Schlüssel','Add your API Key here...'=>'Geben Sie hier Ihren API-Schlüssel ein...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Besuchen Sie <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">diesen Link</a>, um zu erfahren, wie Sie einen API-Schlüssel einrichten, <strong>API-Kosten kontrollieren</strong> und HTTP-Referrer-Einschränkungen festlegen können.','Your HTTP referrer is: %s'=>'Ihr HTTP-Referrer lautet: %s','There was an error on the server processing your Google Translate key.'=>'Bei der Verarbeitung Ihres Google Translate-Schlüssels ist ein Serverfehler aufgetreten.','There was an error with your Google Translate key.'=>'Es ist ein Fehler mit Ihrem Google Translate-Schlüssel aufgetreten.','Please check your TranslatePress license key.'=>'Bitte überprüfen Sie Ihren TranslatePress-Lizenzschlüssel.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Für diese Website wurde keine aktive Lizenz erkannt.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Um die automatische Übersetzung mit TranslatePress AI zu aktivieren, benötigen Sie einen Lizenzschlüssel, den Sie durch die Erstellung eines kostenlosen Kontos erhalten.','Create your Free Account'=>'Erstellen Sie Ihr kostenloses Konto',' or '=>' oder ','Enter your license key'=>'Geben Sie Ihren Lizenzschlüssel ein',' Or %1$spurchase one here%2$s'=>' Oder %1$shier erwerben%2$s','Your free account includes: '=>'Ihr kostenloses Konto umfasst: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Erhalten Sie mehr KI-Wörter und schalten Sie mit TranslatePress Pro alle KI-Funktionen frei.','You have a valid %s <strong>license</strong>.'=>'Sie haben eine gültige %s <strong>Lizenz</strong>.',' words remaining. '=>' Wörter verbleibend. ','Recheck'=>'Erneut prüfen','Rechecking...'=>'Wird erneut geprüft...','Done.'=>'Fertig.','Manage your license & quota on the %s'=>'Verwalten Sie Ihre Lizenz & Ihr Kontingent auf der %s','TranslatePress.com Account Page'=>'TranslatePress.com-Kontoseite','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'SEO-Unterstützung für Seiten-Slug, Seitentitel, Beschreibung sowie Facebook- und Twitter-Social-Graph-Informationen. Das HTML-lang-Attribut wird korrekt gesetzt.','Enable Modules'=>'Module aktivieren','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Aktivieren Sie Add-on-Module, um TranslatePress zu erweitern und die Funktionalität Ihrer übersetzten Website zu verbessern.','More functionality with TranslatePress Pro.'=>'Mehr Funktionalität mit TranslatePress Pro.','Already a Pro User?'=>'Sind Sie bereits Pro-Nutzer?','Activate License Key'=>'Lizenzschlüssel aktivieren','This add-on is not available on your current plan.'=>'Dieses Add-on ist in Ihrem aktuellen Plan nicht verfügbar.','Continue'=>'Weiter','The link you followed has expired. Please reload the page and try again.'=>'Der Link, dem Sie gefolgt sind, ist abgelaufen. Bitte laden Sie die Seite neu und versuchen Sie es erneut.','A valid license is required to enable Automatic Translation.'=>'Eine gültige Lizenz ist erforderlich, um die automatische Übersetzung zu aktivieren.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Ihr Lizenzschlüssel ist für diese URL deaktiviert. Reaktivieren Sie ihn unter <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Websites verwalten.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Lizenzschlüssel stimmt nicht überein.</strong> Die eingegebene Lizenz entspricht nicht der installierten TranslatePress-Version.</p><p>Bitte überprüfen Sie in Ihrem TranslatePress Account, ob Sie die für Ihre Lizenz korrekte Version installiert haben.</p>','Automatically translate your website using TranslatePress AI.'=>'Übersetzen Sie Ihre Website automatisch mit TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'Um die automatische Übersetzung mit TranslatePress AI zu aktivieren, geben Sie bitte Ihren Lizenzschlüssel aus','your account.'=>'Ihrem TranslatePress Account ein.','Skip and continue with manual translation »'=>'Überspringen und mit manueller Übersetzung fortfahren »','Get Your Free TranslatePress AI License'=>'Kostenlose TranslatePress AI-Lizenz erhalten','Generate License'=>'Lizenz erstellen','Creating a free account includes: '=>'Ein kostenloser Account beinhaltet: ','Are you a TranslatePress PRO user?'=>'Sind Sie TranslatePress PRO-Nutzer?','Install & Activate your pro plugin.'=>'Installieren und aktivieren Sie Ihr Pro-Plugin.','Skip this step'=>'Diesen Schritt überspringen','The email address you added is incorrect.'=>'Die von Ihnen eingegebene E-Mail-Adresse ist falsch.','Setup Complete'=>'Einrichtung abgeschlossen','You\'re ready to start translating!'=>'Sie sind bereit, mit dem Übersetzen zu beginnen!','You have successfully set up TranslatePress for your website.'=>'Sie haben TranslatePress erfolgreich für Ihre Website eingerichtet.','Receive '=>'Erhalten ','Yes, send me multilingual growth tips.'=>'Ja, senden Sie mir Tipps für mehrsprachiges Wachstum.','Start translating'=>'Mit dem Übersetzen beginnen','Sign Up and Start translating'=>'Registrieren und mit dem Übersetzen beginnen','Please upload a TranslatePress Pro plugin file.'=>'Bitte laden Sie eine Plugin-Datei von TranslatePress Pro hoch.','Upload error: '=>'Fehler beim Hochladen: ','Install failed: '=>'Installation fehlgeschlagen: ','Plugin installed, but entry file not found. '=>'Plugin installiert, aber Einstiegsdatei nicht gefunden. ','Activation error: '=>'Aktivierungsfehler: ','Invalid plugin specified.'=>'Ungültiges Plugin angegeben.','Invalid action specified.'=>'Ungültige Aktion angegeben.','Plugin deactivation failed.'=>'Deaktivierung des Plugins fehlgeschlagen.','Plugin activation failed: '=>'Aktivierung des Plugins fehlgeschlagen: ','First, install and activate TranslatePress Pro'=>'Installieren und aktivieren Sie zunächst TranslatePress Pro','Please upload the TranslatePress PRO zip archive from your'=>'Bitte laden Sie das ZIP-Archiv von TranslatePress Pro aus Ihrem','TranslatePress Account'=>'TranslatePress Account','Install and Activate'=>'Installieren und aktivieren','Installed Pro versions'=>'Installierte Pro-Versionen','« Go back'=>'« Zurück','Activate License »'=>'Lizenz aktivieren »','You are trying to add an invalid additional language. Please select a valid option.'=>'Sie versuchen, eine ungültige Zusatzsprache hinzuzufügen. Bitte wählen Sie eine gültige Option aus.','Please add an additional language.'=>'Bitte fügen Sie eine zusätzliche Sprache hinzu.','You are trying to add an invalid default language. Please select a valid option.'=>'Sie versuchen, eine ungültige Standardsprache hinzuzufügen. Bitte wählen Sie eine gültige Option aus.','You need to select a default language.'=>'Sie müssen eine Standardsprache auswählen.','Configure Site Languages'=>'Website-Sprachen konfigurieren','Select the default and additional languages for your website.'=>'Wählen Sie die Standardsprache und zusätzliche Sprachen für Ihre Website aus.','You can edit your site languages at any point.'=>'Sie können Ihre Sprachen jederzeit bearbeiten.','Additional Language'=>'Zusätzliche Sprache','Choose a secondary language...'=>'Wählen Sie eine zweite Sprache aus...','Add Language'=>'Sprache hinzufügen','Choose a language...'=>'Wählen Sie eine Sprache aus...','Add more than two languages with TranslatePress Pro.'=>'Fügen Sie mit TranslatePress Pro mehr als zwei Sprachen hinzu.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Manage Sites.'=>'Ihr Lizenzschlüssel ist für diese URL deaktiviert. Reaktivieren Sie ihn unter <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Websites verwalten.','Add your License Key'=>'Lizenzschlüssel hinzufügen','Add your License Key to unlock all premium features. Find the License Key in your'=>'Fügen Sie Ihren Lizenzschlüssel hinzu, um alle Premium-Funktionen freizuschalten. Den Lizenzschlüssel finden Sie in Ihrem','Your license is valid and active.'=>'Ihre Lizenz ist gültig und aktiv.','« Go Back'=>'« Zurück','Set up Language Switcher'=>'Sprachumschalter einrichten','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'Wählen Sie den Stil des Sprachumschalters aus. Weitere Anzeigeoptionen finden Sie in den Plugin-Einstellungen.','Displays a small language drop-down across your website, in a corner of your choosing.'=>'Zeigt ein kleines Sprach-Dropdown auf Ihrer Website in einer Ecke Ihrer Wahl an.','Switcher Location'=>'Position des Umschalters','Apply a Template'=>'Vorlage anwenden','You can customize the design later'=>'Sie können das Design später anpassen','Default Template'=>'Standardvorlage','Dark Template'=>'Dunkle Vorlage','Border Template'=>'Rahmenvorlage','Border'=>'Rahmen','Transparent Template'=>'Transparente Vorlage','Transparent'=>'Transparent','Welcome to TranslatePress'=>'Willkommen bei TranslatePress','Quick guided setup to configure TranslatePress in no time!'=>'Schnelle geführte Einrichtung, um TranslatePress im Handumdrehen zu konfigurieren!','It takes less than a minute.'=>'Es dauert weniger als eine Minute.','Scanning item %1$d of %2$d...'=>'Element %1$d von %2$d wird gescannt...','Manually translated'=>'Manuell übersetzt','Automatically translated'=>'Automatisch übersetzt','Not translated'=>'Nicht übersetzt','Bulk Actions'=>'Mehrfachauswahl','Delete entries'=>'Einträge löschen','Edit'=>'Bearbeiten','Delete'=>'Löschen','Filter'=>'Filtern','Clear filters'=>'Filter zurücksetzen','Add New'=>'Neu hinzufügen','Rescan plugins and theme for strings'=>'Plugins und Theme erneut nach Zeichenketten durchsuchen','Scanning plugins and theme for strings...'=>'Plugins und Theme werden nach Zeichenketten durchsucht...','Plugins and theme scan is complete'=>'Der Scan von Plugins und Theme ist abgeschlossen','Plugins and theme scan did not finish due to an error'=>'Der Scan von Plugins und Theme wurde aufgrund eines Fehlers nicht abgeschlossen','Import / Export'=>'Import / Export','items'=>'Einträge','See More'=>'Mehr anzeigen','See Less'=>'Weniger anzeigen','Apply'=>'Anwenden','No strings match your query.'=>'Keine Zeichenketten entsprechen Ihrer Suchanfrage.','Try to rescan plugins and theme for strings.'=>'Versuchen Sie, Plugins und Theme erneut nach Zeichenketten zu durchsuchen.','An error occurred while loading results. Most likely you were logged out. Reload page?'=>'Beim Laden der Ergebnisse ist ein Fehler aufgetreten. Sie wurden höchstwahrscheinlich abgemeldet. Seite neu laden?','found in translation'=>'In Übersetzung gefunden','Select All'=>'Alle auswählen','Select Visible'=>'Sichtbare auswählen','You are about to perform this action on all the strings matching your filter, not just the visibly checked. To perform the action only to the visible strings click "Select Visible" from the table header dropdown.'=>'Sie sind dabei, diese Aktion für alle Zeichenketten auszuführen, die Ihrem Filter entsprechen, nicht nur für die sichtbar ausgewählten. Um die Aktion nur für die sichtbaren Zeichenketten auszuführen, klicken Sie im Dropdown-Menü der Tabellenkopfzeile auf „Sichtbare auswählen“.','You are about to perform this action only on the visible strings. To perform the action on all the strings matching the filter click "Select All" from the table header dropdown.'=>'Sie sind dabei, diese Aktion nur für die sichtbaren Zeichenketten auszuführen. Um die Aktion für alle Zeichenketten auszuführen, die dem Filter entsprechen, klicken Sie im Dropdown-Menü der Tabellenkopfzeile auf „Alle auswählen“.','To continue please type the word:'=>'Um fortzufahren, geben Sie bitte das Wort ein:','The word typed was incorrect. Action was cancelled.'=>'Das eingegebene Wort war falsch. Die Aktion wurde abgebrochen.','Warning: This action cannot be undone. Deleting a string will remove its current translation. The original string will appear again in this interface after TranslatePress detects it. This action is NOT equivalent to excluding the string from being translated again.'=>'Warnung: Diese Aktion kann nicht rückgängig gemacht werden. Das Löschen einer Zeichenkette entfernt deren aktuelle Übersetzung. Die ursprüngliche Zeichenkette wird in dieser Oberfläche erneut angezeigt, nachdem TranslatePress sie erkannt hat. Diese Aktion ist NICHT gleichbedeutend mit dem Ausschluss der Zeichenkette von einer erneuten Übersetzung.','%d original entries and their translations were deleted.'=>'%d ursprüngliche Einträge und deren Übersetzungen wurden gelöscht.','Navigate to next page'=>'Zur nächsten Seite navigieren','Navigate to previous page'=>'Zur vorherigen Seite navigieren','Navigate to first page'=>'Zur ersten Seite navigieren','Navigate to last page'=>'Zur letzten Seite navigieren','Type a page number to navigate to'=>'Seitenzahl eingeben, zu der navigiert werden soll','Incorrect page number. Type a page number between 1 and total number of pages'=>'Falsche Seitenzahl. Geben Sie eine Seitenzahl zwischen 1 und der Gesamtanzahl der Seiten ein.','Search original and translated strings containing typed keywords while also matching selected filters. Place string in quotes for exact match: "string"'=>'Durchsuchen Sie originale und übersetzte Zeichenketten nach eingegebenen Schlüsselwörtern unter Berücksichtigung der ausgewählten Filter. Setzen Sie eine Zeichenkette in Anführungszeichen, um nach exakter Übereinstimmung zu suchen: „Zeichenkette“','Filter strings according to selected translation status, filters and keywords and selected filters'=>'Zeichenketten nach ausgewähltem Übersetzungsstatus, Filtern und Schlüsselwörtern sowie ausgewählten Filtern filtern','Removes selected filters'=>'Ausgewählte Filter entfernen','See options for selecting all strings'=>'Optionen zum Auswählen aller Zeichenketten anzeigen','Click to sort strings by this column'=>'Klicken Sie, um Zeichenketten nach dieser Spalte zu sortieren','Language in which the translation status filter applies. Leave unselected for the translation status to apply to ANY language'=>'Sprache, auf die der Filter für den Übersetzungsstatus angewendet wird. Lassen Sie diese unausgewählt, damit der Übersetzungsstatus auf JEDE Sprache angewendet wird.','Search'=>'Suchen','Slugs that are not found in either one of the other categories.'=>'Slugs, die in keiner der anderen Kategorien gefunden werden.','Plugins and Theme String Translation'=>'Zeichenkettenübersetzung für Plugins und Theme','Gettext'=>'Gettext','Search Gettext Strings'=>'Gettext-Zeichenketten durchsuchen','ID'=>'ID','Original String'=>'Original-String','Translation'=>'Übersetzung','Filter by domain'=>'Nach Domain filtern','Filter by type'=>'Nach Typ filtern','Email text'=>'E-Mail-Text','Emails String Translation'=>'E-Mail-String-Übersetzung','Emails'=>'E-Mails','Search Email Strings'=>'E-Mail-Strings durchsuchen','User Inputted String Translation'=>'Benutzereingabe-String-Übersetzung','Regular'=>'Regulär','Search Regular Strings'=>'Reguläre Strings durchsuchen','Filter by Translation Block'=>'Nach Übersetzungsblock filtern','URL Slugs Translation'=>'URL-Slug-Übersetzung','String Translation Editor'=>'String-Übersetzungseditor','TranslatePress has detected and cleaned up some failed translation entries in your database following %1$san isolated incident%2$s. No further action is required.'=>'TranslatePress hat im Anschluss an %1$seinen isolierten Vorfall%2$s einige fehlgeschlagene Übersetzungseinträge in Ihrer Datenbank erkannt und bereinigt. Es ist keine weitere Aktion erforderlich.','Post Slug'=>'Beitrags-Slug','Invalid language code'=>'Ungültiger Sprachcode','First by browser language, then IP address (recommended)'=>'Zuerst anhand der Browsersprache, dann anhand der IP-Adresse (empfohlen)','First by IP address, then by browser language'=>'Zuerst anhand der IP-Adresse, dann anhand der Browsersprache','Only by browser language'=>'Nur anhand der Browsersprache','Only by IP address'=>'Nur anhand der IP-Adresse','A popup appears asking the user if they want to be redirected'=>'Es erscheint ein Popup, in dem der Benutzer gefragt wird, ob er weitergeleitet werden möchte','Redirect directly (*not recommended)'=>'Direkt weiterleiten (*nicht empfohlen)','Pop-up window over the content'=>'Popup-Fenster über dem Inhalt','Hello bar before the content'=>'Hinweisleiste vor dem Inhalt','WARNING. Cannot determine your language preference based on your current IP.<br>This is most likely because the website is on a local environment.'=>'WARNUNG. Ihre Spracheinstellung kann anhand Ihrer aktuellen IP-Adresse nicht ermittelt werden.<br>Dies liegt höchstwahrscheinlich daran, dass die Website in einer lokalen Umgebung betrieben wird.','Go to <a href="%s" target="_self">Advanced</a> tab to change this feature\'s settings'=>'Wechseln Sie zur Registerkarte <a href="%s" target="_self">Erweitert</a>, um die Einstellungen dieser Funktion zu ändern.','User Language Detection Method'=>'Methode zur Erkennung der Benutzersprache','Select how the language should be detected for first time visitors.<br>The visitor\'s last displayed language will be remembered through cookies.'=>'Wählen Sie aus, wie die Sprache für Erstbesucher erkannt werden soll.<br>Die zuletzt angezeigte Sprache des Besuchers wird über Cookies gespeichert.','User Notification Popup'=>'Benachrichtigungs-Popup','A popup appears asking the user if they want to be redirected.'=>'Es erscheint ein Popup, in dem der Benutzer gefragt wird, ob er weitergeleitet werden möchte.','Popup Type'=>'Popup-Typ','Popup Text'=>'Popup-Text','The same text is displayed in all languages. <br>A selecting language switcher will be appended to the pop-up. The detected language is pre-selected.'=>'Der gleiche Text wird in allen Sprachen angezeigt. <br>Ein Sprachumschalter wird dem Popup hinzugefügt. Die erkannte Sprache ist vorausgewählt.','Button Text'=>'Button-Text','Write the text you wish to appear on the button..'=>'Geben Sie den Text ein, der auf dem Button erscheinen soll..','Close Button Text'=>'Schließen-Button-Text','Write the text you wish to appear on the close button. Leave empty for just the close button.'=>'Geben Sie den Text ein, der auf dem Schließen-Button erscheinen soll. Lassen Sie das Feld leer, um nur den Schließen-Button anzuzeigen.','Bad request. There was an error accessing the DeepL API.'=>'Ungültige Anfrage. Beim Zugriff auf die DeepL API ist ein Fehler aufgetreten.','The API key entered is invalid.'=>'Der eingegebene API-Schlüssel ist ungültig.','The API resource could not be found.'=>'Die API-Ressource konnte nicht gefunden werden.','The request size is too large.'=>'Die Anfragegröße ist zu groß.','The request is too long.'=>'Die Anfrage ist zu lang.','Too many requests. Please try again later.'=>'Zu viele Anfragen. Bitte versuchen Sie es später erneut.','Your translation quota has been reached.'=>'Ihr Übersetzungskontingent wurde erreicht.','We could not process your request. Please try again later.'=>'Wir konnten Ihre Anfrage nicht verarbeiten. Bitte versuchen Sie es später erneut.','There is an error on the DeepL service and your request could not be processed.'=>'Auf dem DeepL-Dienst ist ein Fehler aufgetreten und Ihre Anfrage konnte nicht verarbeitet werden.','DeepL API Type'=>'DeepL API-Typ','Pro'=>'Pro','Free'=>'Free','Select the type of DeepL API you want to use.'=>'Wählen Sie den Typ der DeepL API aus, den Sie verwenden möchten.','DeepL API Key'=>'DeepL API-Schlüssel','Visit <a href="%s" target="_blank">this link</a> to see how you can set up an API key and control API costs.'=>'Besuchen Sie <a href="%s" target="_blank">diesen Link</a>, um zu erfahren, wie Sie einen API-Schlüssel einrichten und API-Kosten kontrollieren können.','Translator'=>'Übersetzer',' TranslatePress Settings'=>' TranslatePress-Einstellungen','Allow this user to translate the website.'=>'Diesem Benutzer erlauben, die Website zu übersetzen.','(inactive)'=>'(inaktiv)','Taxonomy Slugs'=>'Taxonomie-Slugs','Search Taxonomy Slugs'=>'Taxonomie-Slugs durchsuchen','Taxonomy Slug'=>'Taxonomie-Slug','Term Slugs'=>'Begriffs-Slugs','Search Term Slugs'=>'Begriffs-Slugs durchsuchen','Term Slug'=>'Begriffs-Slug','Taxonomy'=>'Taxonomie','Filter by Taxonomy'=>'Nach Taxonomie filtern','Post Slugs'=>'Beitrags-Slugs','Search Post Slugs'=>'Beitrags-Slugs durchsuchen','Post ID'=>'Beitrags-ID','Post Type'=>'Beitragstyp','Filter by Post Type'=>'Nach Beitragstyp filtern','Published'=>'Veröffentlicht','Any Post Status'=>'Beliebiger Beitragsstatus','Post Type Base Slugs'=>'Beitragstyp-Basis-Slugs','Post Type Base Slug'=>'Beitragstyp-Basis-Slug','Search Post Type Base Slugs'=>'Beitragstyp-Basis-Slugs durchsuchen','WooCommerce Slugs'=>'WooCommerce-Slugs','WooCommerce Slug'=>'WooCommerce-Slug','Search WooCommerce Slugs'=>'WooCommerce-Slugs durchsuchen','Other Slugs'=>'Andere Slugs','Search Other Slugs'=>'Andere Slugs durchsuchen','Verbiage for the DeepL Pro Add-onTranslatePress Pro Add-on'=>'TranslatePress Pro Add-on','Verbiage for the DeepL Pro Add-onAddons tab'=>'Add-ons-Reiter','page 1 of 3of'=>'/','Untranslated in this languagein'=>'in']];